def download_crohme():
    """Download CROHME datasets with multiple mirrors"""
    crohme_dir = os.path.join(config.data_dir, "crohme")
    os.makedirs(crohme_dir, exist_ok=True)

    # CROHME mirrors and sources
    crohme_sources = [
        # Primary source - Official CROHME
        {
            "name": "CROHME 2014",
            "train": "http://www.iapr-tc11.org/mediawiki/index.php/CROHME_2014_Competition_Download",
            "alt": "https://www.kaggle.com/datasets/rtatman/crohme2014"
        },
        # Kaggle mirrors
        {
            "name": "Kaggle CROHME",
            "url": "https://www.kaggle.com/datasets/ltaverne/crohme-2016"
        },
        # Backup mirror
        {
            "name": "HuggingFace Mirror",
            "url": "https://huggingface.co/datasets/project-sloth/crohme-dataset"
        }
    ]

    print("="*60)
    print("DOWNLOADING CROHME DATASET")
    print("="*60)

    # Try direct download from various sources
    direct_urls = [
        # CROHME 2014 Training
        "http://www.iapr-tc11.org/dataset/CROHME-2014/CROHME2014_data_and_gt.zip",
        # CROHME 2016
        "http://www.iapr-tc11.org/dataset/CROHME-2016/CROHME2016_data_and_gt.zip",
        # CROHME 2019
        "http://www.iapr-tc11.org/dataset/CROHME-2019/CROHME2019_data_and_gt.zip",
    ]

    for url in direct_urls:
        filename = url.split('/')[-1]
        output_path = os.path.join(crohme_dir, filename)

        if os.path.exists(output_path):
            print(f"Already downloaded: {filename}")
            continue

        print(f"\nTrying: {url}")
        if download_file(url, output_path, filename):
            extract_archive(output_path, crohme_dir)
        else:
            print(f"Failed: {url}")

    return crohme_dir

def download_hme100k():
    """Download HME100K dataset"""
    hme_dir = os.path.join(config.data_dir, "hme100k")
    os.makedirs(hme_dir, exist_ok=True)

    print("\n" + "="*60)
    print("DOWNLOADING HME100K DATASET")
    print("="*60)

    # HME100K sources
    hme_urls = [
        "https://huggingface.co/datasets/chenxingqiang/HME100K/resolve/main/HME100K.zip",
        "https://drive.google.com/uc?id=1lRz4DcEOrzSlLBhXOKM5qeEI6VKa2Mqb",
        "https://github.com/lsqun/HME100K/releases/download/v1.0/HME100K.zip"
    ]

    output_path = os.path.join(hme_dir, "HME100K.zip")

    if os.path.exists(output_path):
        print("HME100K already downloaded")
    else:
        for url in hme_urls:
            print(f"\nTrying: {url}")
            if 'drive.google.com' in url:
                try:
                    gdown.download(url, output_path, quiet=False)
                    break
                except:
                    continue
            elif download_file(url, output_path, "HME100K"):
                break

        if os.path.exists(output_path):
            extract_archive(output_path, hme_dir)

    return hme_dir

