class CROHMEDataset(MathExpressionDataset):
    """CROHME dataset loader"""

    def _load_data(self):
        """Load CROHME data from InkML files"""
        import xml.etree.ElementTree as ET

        crohme_path = os.path.join(self.data_dir, 'CROHME')
        if not os.path.exists(crohme_path):
            crohme_path = self.data_dir

        # Find all InkML files
        inkml_files = []
        for root, dirs, files in os.walk(crohme_path):
            for f in files:
                if f.endswith('.inkml'):
                    inkml_files.append(os.path.join(root, f))

        print(f"Found {len(inkml_files)} InkML files in {crohme_path}")

        # Parse InkML files
        for inkml_path in tqdm(inkml_files, desc=f"Loading CROHME {self.split}"):
            try:
                tree = ET.parse(inkml_path)
                root_elem = tree.getroot()

                # Get LaTeX annotation
                latex = None
                for annotation in root_elem.findall('.//{http://www.w3.org/2003/InkML}annotation'):
                    if annotation.get('type') == 'truth':
                        latex = annotation.text.strip()
                        break

                if not latex:
                    continue

                # Check for pre-rendered image
                img_path = inkml_path.replace('.inkml', '.png')
                if not os.path.exists(img_path):
                    # Render from strokes
                    img_path = self._render_inkml(inkml_path, root_elem)

                if img_path and os.path.exists(img_path):
                    self.samples.append({
                        'image_path': img_path,
                        'latex': latex
                    })

            except Exception as e:
                continue

        print(f"Loaded {len(self.samples)} CROHME samples for {self.split}")

    def _render_inkml(self, inkml_path: str, root_elem) -> str:
        """Render InkML strokes to image"""
        try:
            # Extract strokes
            strokes = []
            for trace in root_elem.findall('.//{http://www.w3.org/2003/InkML}trace'):
                points = trace.text.strip().split(',')
                stroke = []
                for pt in points:
                    coords = pt.strip().split()
                    if len(coords) >= 2:
                        x, y = float(coords[0]), float(coords[1])
                        stroke.append((x, y))
                if stroke:
                    strokes.append(stroke)

            if not strokes:
                return None

            # Find bounding box
            all_points = [p for stroke in strokes for p in stroke]
            xs = [p[0] for p in all_points]
            ys = [p[1] for p in all_points]
            min_x, max_x = min(xs), max(xs)
            min_y, max_y = min(ys), max(ys)

            # Scale and render
            scale = min(200 / (max_x - min_x + 1), 60 / (max_y - min_y + 1))
            offset = 10

            img = Image.new('L', (config.img_width, config.img_height), color=255)
            draw = ImageDraw.Draw(img)

            for stroke in strokes:
                scaled_stroke = [
                    (int((x - min_x) * scale + offset), 
                     int((y - min_y) * scale + offset))
                    for x, y in stroke
                ]
                if len(scaled_stroke) > 1:
                    draw.line(scaled_stroke, fill=0, width=2)

            # Save image
            img_path = inkml_path.replace('.inkml', '.png')
            img.save(img_path)
            return img_path

        except Exception as e:
            return None


class HME100KDataset(MathExpressionDataset):
    """HME100K dataset loader"""

    def _load_data(self):
        """Load HME100K data"""
        hme_path = os.path.join(self.data_dir, 'HME100K')
        if not os.path.exists(hme_path):
            hme_path = self.data_dir

        # Look for annotation file
        anno_file = None
        for name in ['train.txt', 'test.txt', 'labels.txt', 'annotation.txt']:
            path = os.path.join(hme_path, name)
            if os.path.exists(path):
                anno_file = path
                break

        if not anno_file:
            # Try subdirectories
            for subdir in ['train', 'test', 'data']:
                subpath = os.path.join(hme_path, subdir)
                if os.path.exists(subpath):
                    for name in ['labels.txt', 'annotation.txt', 'gt.txt']:
                        path = os.path.join(subpath, name)
                        if os.path.exists(path):
                            anno_file = path
                            hme_path = subpath
                            break

        if not anno_file:
            print(f"Warning: No annotation file found in {hme_path}")
            return

        # Load annotations
        with open(anno_file, 'r', encoding='utf-8') as f:
            for line in tqdm(f, desc=f"Loading HME100K {self.split}"):
                parts = line.strip().split('\t')
                if len(parts) >= 2:
                    img_name = parts[0]
                    latex = parts[1]

                    img_path = os.path.join(hme_path, img_name)
                    if not os.path.exists(img_path):
                        img_path = os.path.join(hme_path, 'images', img_name)

                    if os.path.exists(img_path):
                        self.samples.append({
                            'image_path': img_path,
                            'latex': latex
                        })

        print(f"Loaded {len(self.samples)} HME100K samples for {self.split}")


class Im2LaTeXDataset(MathExpressionDataset):
    """Im2LaTeX dataset for pretraining"""

    def _load_data(self):
        """Load Im2LaTeX data"""
        im2latex_path = os.path.join(self.data_dir, 'formula_images')
        if not os.path.exists(im2latex_path):
            im2latex_path = self.data_dir

        # Look for annotation file
        anno_file = None
        for name in ['train.txt', 'formulas.txt', 'im2latex_formulas.txt']:
            path = os.path.join(im2latex_path, name)
            if os.path.exists(path):
                anno_file = path
                break

        if not anno_file:
            print(f"Warning: No annotation file found in {im2latex_path}")
            return

        # Load annotations
        with open(anno_file, 'r', encoding='utf-8', errors='ignore') as f:
            for line in tqdm(f, desc=f"Loading Im2LaTeX {self.split}"):
                parts = line.strip().split('\t')
                if len(parts) >= 2:
                    img_name = parts[0]
                    latex = parts[1]

                    img_path = os.path.join(im2latex_path, img_name)
                    if os.path.exists(img_path):
                        self.samples.append({
                            'image_path': img_path,
                            'latex': latex
                        })

        print(f"Loaded {len(self.samples)} Im2LaTeX samples for {self.split}")
